import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
//import { register } from "../../utils/auth";
import Button from "../common/Button";
import ErrorMessage from "../common/ErrorMessage/ErrorMessage";
import Input from "../common/Input";
import "./RegisterForm.css";
import { getProfile, register } from "../../services/userService";

export default function RegisterForm({ onSuccess }) {
    const [displayName, setDisplayName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [verifyPassword, setVerifyPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const navigate = useNavigate();


    const validateEmail = (email) => {
        return email.match(
            /^(([^<>()[\]\\.,;:\s@\"]+(\.[^<>()[\]\\.,;:\s@\"]+)*)|(\".+\"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
        );
    };




    const validateForm = () => {
        if (validateEmail(email)) {
            setError(
                "Parece que el Email que colocaste es incorrecto");
            return false;
        }
        if (password !== verifyPassword) {
            setError("Parece que tus contraseñas no coinciden o estan vacias")
            return false;
        }
};

/* const onSubmit =  sync (e) => {
    e.preventDefault();

if(!e.currentTarget.checkValidity()){
    e.currentTarget.reportValidity();
    return;
}

if(!validateForm()) 
    return;

    setLoading(true);
    try {
            await register(displayName, email, password);

            window.location.reload();
    } catch (err) {
        setError(err.message);
    } finally {
        setLoading(false);
    }
}; */


return (
    <div className="register-container">
        <div className="register-card">
            <h2>Registrar Usuario</h2>
            <form className="register-form" onSubmit={onSubmit}>
                 <div className="form-group">
                    <Input
                        id="email2"
                        label="Email2: "
                        type="email"
                        value={email}
                        onChange={(event) => setEmail(event.target.value)}
                        placeholder="Ingresa tu email2"
                        required
                    />
                </div>
                <div className="form-group">
                    <Input
                        id="email"
                        label="Email: "
                        type="email"
                        value={email}
                        onChange={(event) => setEmail(event.target.value)}
                        placeholder="Ingresa tu email"
                        required
                    />
                </div>
                <div className="form-group">
                    <Input
                        id="password"
                        label="Contraseña: "
                        type="password"
                        value={password}
                        onChange={(event) => setPassword(event.target.value)}
                        placeholder="Ingresa tu contraseña"
                        required
                    />
                </div>

                {error && <ErrorMessage>{error}</ErrorMessage>}

                <Button disabled={loading} type="submit" variant="primary">
                    {loading ? "Iniciando sesión..." : "Iniciar Sesión"}
                </Button>
            </form>
            <div className="register-footer">
                <Link to="/">Volver al inicio</Link>
            </div>
        </div>
    </div>
);
}
